#include <bits/stdc++.h>
using namespace std;
int n,a[102];
bool use[10004],f[10004];
int main(){
    memset(use,1,sizeof(use));
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        int cnt=0,sum=0;
        while(1){
            cnt++;
            scanf("%d",&a[cnt]);
            if(a[cnt]<0){
                cnt--;
                break;
            }
            sum+=a[cnt];
        }
        memset(f,0,sizeof(f));
        f[0]=1;
        for(int i=1;i<=cnt;i++)
            for(int j=sum;j>=a[i];j--)
                f[j]=max(f[j],f[j-a[i]]);
        for(int i=1;i<=10000;i++)
            use[i]&=f[i];
    }
    for(int i=10000;i>=0;i--)
        if(use[i]){
            printf("%d",i);
            break;
        }
    return 0;
}
